/// READ MODIFICATION
fn modification_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_modification.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(90);
            if _len > 0 { let _end = _len.min(0+6); state.command = String::from_utf8_lossy(&_bytes[0.._end]).to_string().cobol_into(); }
            if _len > 7 { let _end = _len.min(7+5); let _s = String::from_utf8_lossy(&_bytes[7.._end]).trim().to_string(); state.a_field = _s.cobol_into(); }
            if _len > 12 { let _end = _len.min(12+5); state.a_alpha = String::from_utf8_lossy(&_bytes[12.._end]).to_string().cobol_into(); }
            if _len > 21 { let _end = _len.min(21+5); let _s = String::from_utf8_lossy(&_bytes[21.._end]).trim().to_string(); state.b_field = _s.cobol_into(); }
            if _len > 26 { let _end = _len.min(26+5); state.b_alpha = String::from_utf8_lossy(&_bytes[26.._end]).to_string().cobol_into(); }
            state._fs_modification = FileStatus::Success;
        }
        Err(FileStatus::AtEnd) => {
            state._fs_modification = FileStatus::AtEnd;
        }
        Err(e) => {
            state._fs_modification = e.clone();
        }
    }
    Ok(())
}

/// WRITE to MODIFICATION
fn modification_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 90];
    { let _src = state.command.as_bytes(); let _end = (0+6).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.a_field, width = 5); let _b = _s.as_bytes(); let _cl = _b.len().min(5); _buf[7..7+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.a_alpha.as_bytes(); let _end = (12+5).min(_buf.len()); let _cl = _src.len().min(_end-12); _buf[12..12+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.b_field, width = 5); let _b = _s.as_bytes(); let _cl = _b.len().min(5); _buf[21..21+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.b_alpha.as_bytes(); let _end = (26+5).min(_buf.len()); let _cl = _src.len().min(_end-26); _buf[26..26+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_modification.write_record(&_buf) {
        Ok(()) => state._fs_modification = FileStatus::Success,
        Err(e) => state._fs_modification = e,
    }
}

/// CLOSE MODIFICATION
fn modification_close(state: &mut ProgramState) {
    match state._fh_modification.close() {
        Ok(()) => state._fs_modification = FileStatus::Success,
        Err(e) => state._fs_modification = e,
    }
}

/// DELETE MODIFICATION
fn modification_delete(state: &mut ProgramState) {
    state._fs_modification = FileStatus::Success; // DELETE stub
}

